class Solution(object):
    def lengthAfterTransformations(self, s, t, nums):
        MOD = 10**9 + 7
        # Build 26x26 transformation matrix
        # M[j][i] = number of times char i produces char j in one step
        # char i produces chars (i+1) % 26, ..., (i+nums[i]) % 26
        M = [[0]*26 for _ in range(26)]
        for i in range(26):
            for k in range(1, nums[i] + 1):
                j = (i + k) % 26
                M[j][i] = (M[j][i] + 1) % MOD
        def mat_mul(A, B):
            C = [[0]*26 for _ in range(26)]
            for i in range(26):
                for k in range(26):
                    if A[i][k] == 0:
                        continue
                    for j in range(26):
                        C[i][j] = (C[i][j] + A[i][k] * B[k][j]) % MOD
            return C
        def mat_pow(M, p):
            result = [[1 if i==j else 0 for j in range(26)] for i in range(26)]
            while p:
                if p & 1:
                    result = mat_mul(result, M)
                M = mat_mul(M, M)
                p >>= 1
            return result
        Mt = mat_pow(M, t)
        count = [0] * 26
        for c in s:
            count[ord(c) - ord('a')] += 1
        total = 0
        for i in range(26):
            for j in range(26):
                total = (total + Mt[i][j] * count[j]) % MOD
        return total
